from pathlib import Path

path = Path('c:/Users/hatha/J2EE_MobileStore/src/main/webapp/WEB-INF/views/admin/product/add.jsp')
text = path.read_text(encoding='utf-8')

old_color = '                            <input type="text" class="admin-form-control" id="color" name="color" maxlength="50" value="${param.color}" placeholder="Ví dụ: Đen, Bạc, Xanh">\n                            </div>\n'
new_color = '                            <input type="text" class="admin-form-control" id="color" name="color" maxlength="50" value="${param.color}" placeholder="Ví dụ: Đen, Bạc, Xanh">\n                            <div class="admin-color-preview" id="colorPreviewWrapper" style="display: ${empty param.color ? \'none\' : \'flex\'}; flex-wrap: wrap; gap:0.75rem; margin-top:0.75rem;">\n                                <div id="colorPreviewContainer" style="display:flex; flex-wrap: wrap; gap:0.75rem;\"></div>\n                            </div>\n                            </div>\n'
if old_color not in text:
    raise RuntimeError('color block marker not found')
text = text.replace(old_color, new_color, 1)

start = text.index('<script>\n    document.addEventListener(\'DOMContentLoaded\', function() {')
end = text.index('</script>\n\n<script>', start) + len('</script>\n\n<script>')
new_script = '''<script>\n    document.addEventListener('DOMContentLoaded', function() {\n        var colorInput = document.getElementById('color');\n        var previewWrapper = document.getElementById('colorPreviewWrapper');\n        var previewContainer = document.getElementById('colorPreviewContainer');\n\n        var colorMap = {\n            "đen": "#111827",\n            "den": "#111827",\n            "trắng": "#FFFFFF",\n            "trang": "#FFFFFF",\n            "bạc": "#C0C0C0",\n            "bac": "#C0C0C0",\n            "xám": "#6B7280",\n            "xam": "#6B7280",\n            "đỏ": "#EF4444",\n            "do": "#EF4444",\n            "xanh dương": "#2563EB",\n            "xanh duong": "#2563EB",\n            "xanh lá": "#10B981",\n            "xanh la": "#10B981",\n            "xanh lục": "#10B981",\n            "xanh luc": "#10B981",\n            "tím": "#8B5CF6",\n            "tim": "#8B5CF6",\n            "hồng": "#EC4899",\n            "hong": "#EC4899",\n            "vàng": "#F59E0B",\n            "vang": "#F59E0B",\n            "cam": "#FB923C",\n            "nâu": "#92400E",\n            "nau": "#92400E",\n            "xanh ngọc": "#14B8A6",\n            "xanh ngoc": "#14B8A6",\n            "xanh rêu": "#65A30D",\n            "xanh reu": "#65A30D",\n            "hồng nhạt": "#F9A8D4",\n            "hong nhat": "#F9A8D4",\n            "xám đậm": "#374151",\n            "xam dam": "#374151",\n            "trắng sữa": "#F8FAFC",\n            "trang sua": "#F8FAFC"\n        };\n\n        function getCssColor(label) {\n            var normalized = label.trim().toLowerCase().normalize('NFD').replace(/[\\u0300-\\u036f]/g, '');\n            normalized = normalized.replace(/[^a-z0-9 ]+/g, ' ').replace(/\\s+/g, ' ').trim();\n            return colorMap[normalized] || label;\n        }\n\n        function renderColorPreview() {\n            var value = colorInput.value.trim();\n            previewContainer.innerHTML = '';\n\n            if (value.length === 0) {\n                previewWrapper.style.display = 'none';\n                return;\n            }\n\n            previewWrapper.style.display = 'flex';\n            var colors = value.split(/[,;/]+/).map(function(token) { return token.trim(); }).filter(function(token) { return token.length > 0; });\n\n            colors.forEach(function(colorLabel) {\n                var cssColor = getCssColor(colorLabel);\n                var option = document.createElement('div');\n                option.className = 'product-color-option';\n                option.title = colorLabel;\n\n                var swatch = document.createElement('div');\n                swatch.className = 'product-color-swatch';\n                swatch.style.background = cssColor;\n                swatch.style.border = cssColor === 'transparent' ? '1px solid #D1D5DB' : '1px solid rgba(0, 0, 0, 0.08)';\n\n                var label = document.createElement('div');\n                label.className = 'product-color-name';\n                label.textContent = colorLabel;\n\n                option.appendChild(swatch);\n                option.appendChild(label);\n                previewContainer.appendChild(option);\n            });\n        }\n\n        colorInput.addEventListener('input', renderColorPreview);\n        renderColorPreview();\n    });\n</script>\n\n<script>'''
text = text[:start] + new_script + text[end:]
path.write_text(text, encoding='utf-8')
print('patched')
